    /// <param name="arr2">Second array of integers</param>
    /// <returns>Length of the longest common contiguous subarray</returns>
    public static int Solve(int[] arr1, int[] arr2)
    {
        int n = arr1.Length;
        int m = arr2.Length;
        int maxLen = 0;

        int[,] dp = new int[n + 1, m + 1];

        for (int i = 1; i <= n; i++)
