            {
                if (arr1[i - 1] == arr2[j - 1])
                {
                    dp[i, j] = dp[i - 1, j - 1] + 1;
                    if (dp[i, j] > maxLen)
                    {
                        maxLen = dp[i, j];
                    }
                }
                else
                {
                    dp[i, j] = 0;
                }
            }
        }

        return maxLen;
    }

    static void Main(string[] args)
