// LongestCommonSubstring finds the length of the longest contiguous subarray
// common to both arrays.
func LongestCommonSubstring(arr1 []int, arr2 []int) int {
	n := len(arr1)
	m := len(arr2)
	maxLen := 0

	dp := make([][]int, n+1)
	for i := range dp {
		dp[i] = make([]int, m+1)
	}

	for i := 1; i <= n; i++ {
		for j := 1; j <= m; j++ {
			if arr1[i-1] == arr2[j-1] {
				dp[i][j] = dp[i-1][j-1] + 1
				if dp[i][j] > maxLen {
					maxLen = dp[i][j]
				}
			} else {
				dp[i][j] = 0
			}
		}
	}

	return maxLen
}

